'use client';
import { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { usuariosService } from '@/services/usuariosServices';
import { useAuth } from '@/hooks/useAuth';

export default function UsuarioPerfilPage() {
  // Obtener parámetros de la URL
  const params = useParams();
  const router = useRouter();
  const { user } = useAuth();
  
  // 👇 DEPURACIÓN EXTREMA
  console.log('🔥 ===== DEPURACIÓN COMPLETA =====');
  console.log('🔥 params completo:', params);
  console.log('🔥 params.id:', params?.id);
  console.log('🔥 user del contexto:', user);
  console.log('🔥 user?.id:', user?.id);
  
  const id = params?.id;
  
  const [usuario, setUsuario] = useState(null);
  const [locales, setLocales] = useState([]);
  const [platos, setPlatos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const cargarUsuario = async () => {
      console.log('🔥 useEffect ejecutándose');
      console.log('🔥 id actual:', id);
      
      // Validación 1: ¿existe id?
      if (!id) {
        console.error('🔥 No hay ID en la URL');
        setError('No hay ID en la URL');
        setLoading(false);
        return;
      }

      // Validación 2: convertir a número
      const userId = Number(id);
      console.log('🔥 userId convertido:', userId);
      console.log('🔥 ¿es NaN?', isNaN(userId));
      
      if (isNaN(userId) || userId <= 0) {
        console.error('🔥 ID inválido:', id);
        setError(`ID inválido: ${id}`);
        setLoading(false);
        return;
      }

      try {
        setLoading(true);
        console.log('🔥 llamando a API con ID:', userId);
        
        // Llamada directa a fetch para ver qué pasa
        const url = `https://api-react-taller-production.up.railway.app/api/users/${userId}`;
        console.log('🔥 URL completa:', url);
        
        const response = await fetch(url, {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('token')}`
          }
        });
        
        console.log('🔥 Status:', response.status);
        
        const text = await response.text();
        console.log('🔥 Respuesta texto:', text);
        
        let data;
        try {
          data = JSON.parse(text);
          console.log('🔥 Respuesta JSON:', data);
        } catch (e) {
          console.error('🔥 No es JSON:', text);
          setError('Respuesta no válida de la API');
          setLoading(false);
          return;
        }
        
        // Procesar datos
        setUsuario(data.user || data);
        setLocales(data.locals || []);
        setPlatos(data.dishes || []);
        
      } catch (err) {
        console.error('🔥 Error en fetch:', err);
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    cargarUsuario();
  }, [id]);

  // Renderizado de depuración
  return (
    <div style={{ padding: '2rem', fontFamily: 'monospace' }}>
      <h1 style={{ fontSize: '1.5rem', marginBottom: '1rem' }}>🔍 DEPURACIÓN</h1>
      
      <div style={{ background: '#f0f0f0', padding: '1rem', borderRadius: '0.5rem', marginBottom: '1rem' }}>
        <h2>Estado actual:</h2>
        <pre style={{ background: '#fff', padding: '1rem', borderRadius: '0.25rem' }}>
          {JSON.stringify({
            id: id,
            loading,
            error,
            usuario: usuario ? { id: usuario.id, username: usuario.username } : null,
            localesCount: locales.length,
            platosCount: platos.length
          }, null, 2)}
        </pre>
      </div>

      <div style={{ background: '#f0f0f0', padding: '1rem', borderRadius: '0.5rem' }}>
        <h2>Logs en consola:</h2>
        <p>Abre la consola (F12) para ver más detalles</p>
        <p>Network tab → Filtra por "users" para ver la llamada a la API</p>
      </div>

      <button 
        onClick={() => router.push('/')}
        style={{
          marginTop: '1rem',
          padding: '0.5rem 1rem',
          background: '#6b21a8',
          color: 'white',
          border: 'none',
          borderRadius: '0.375rem',
          cursor: 'pointer'
        }}
      >
        Volver al inicio
      </button>
    </div>
  );
}